object ConfigXmlParser {

  private def createSecureSAXParser(): SAXParser = {
    val factory = SAXParserFactory.newInstance()
    // Disable external entities to prevent XXE attacks
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", false)
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    factory.newSAXParser()
  }

  def parseConfig(xmlString: String): Either[String, ParsedConfig] = {
    Try {
      val parser = createSecureSAXParser()
      val xmlDoc = XML.withSAXParser(parser).loadString(xmlString)
      extractConfig(xmlDoc)
    } match {
      case Success(config) => Right(config)
      case Failure(ex) => Left(s"Failed to parse XML configuration: ${ex.getMessage}")
    }
  }

  private def extractConfig(root: Elem): ParsedConfig = {
    val configName = (root \@ "name") match {
      case "" => root.label
      case name => name
    }

    val version = (root \@ "version") match {
      case "" => None
      case v => Some(v)
    }

    val metadata = extractMetadata(root)
    val sections = extractSections(root)

    ParsedConfig(
      name = configName,
      version = version,
      sections = sections,
      metadata = metadata
    )
  }

  private def extractMetadata(root: Elem): Map[String, String] = {
    val metadataNode = root \ "metadata"
    if (metadataNode.isEmpty) {
      Map.empty
    } else {
      metadataNode.head.child.collect {
        case elem: Elem => elem.label -> elem.text.trim
      }.toMap
    }
  }

  private def extractSections(root: Elem): List[ConfigSection] = {
    val sections = root \ "section"
    if (sections.isEmpty) {
      // If no explicit sections, treat all <setting> elements under root as a default section
      val settings = extractSettings(root)
      if (settings.nonEmpty) {
        List(ConfigSection("default", settings))
      } else {
        List.empty
      }
    } else {
      sections.map { sectionNode =>
        val sectionName = (sectionNode \@ "name") match {
          case "" => "unnamed"
          case name => name
        }
        val settings = extractSettings(sectionNode)
        ConfigSection(sectionName, settings)
      }.toList
    }
  }

  private def extractSettings(parent: NodeSeq): List[ConfigSetting] = {
    (parent \ "setting").map { settingNode =>
      val key = (settingNode \@ "key") match {
        case "" => (settingNode \ "key").text.trim
        case k => k
      }

      val value = (settingNode \@ "value") match {
        case "" => (settingNode \ "value").headOption.map(_.text.trim).getOrElse(settingNode.text.trim)
        case v => v
      }

      val settingType = (settingNode \@ "type") match {
        case "" => (settingNode \ "type").headOption.map(_.text.trim).getOrElse("string")
        case t => t
      }

      val description = (settingNode \@ "description") match {
        case "" => (settingNode \ "description").headOption.map(_.text.trim)
        case d => Some(d)
      }

      ConfigSetting(key, value, settingType, description)
    }.toList
  }

  def extractSettingByKey(xmlString: String, key: String): Either[String, Option[ConfigSetting]] = {
    parseConfig(xmlString).map { config =>
      config.sections.flatMap(_.settings).find(_.key == key)
    }
  }

  def extractSettingsBySection(xmlString: String, sectionName: String): Either[String, List[ConfigSetting]] = {
    parseConfig(xmlString).map { config =>
      config.sections.filter(_.name == sectionName).flatMap(_.settings)
    }
  }

  def validateConfig(xmlString: String): Either[String, List[String]] = {
    parseConfig(xmlString).map { config =>
      val warnings = mutable.ListBuffer[String]()

      if (config.version.isEmpty) {
        warnings += "Configuration has no version attribute"
      }

      if (config.sections.isEmpty) {
        warnings += "Configuration has no sections or settings"
      }

      config.sections.foreach { section =>
        if (section.settings.isEmpty) {
          warnings += s"Section '${section.name}' has no settings"
        }
        section.settings.foreach { setting =>
          if (setting.key.isEmpty) {
            warnings += s"Found setting with empty key in section '${section.name}'"
          }
          if (setting.value.isEmpty) {
            warnings += s"Setting '${setting.key}' in section '${section.name}' has empty value"
          }
        }

        // Check for duplicate keys within a section
        val keys = section.settings.map(_.key)
        val duplicates = keys.diff(keys.distinct)
        if (duplicates.nonEmpty) {
          warnings += s"Section '${section.name}' has duplicate keys: ${duplicates.mkString(", ")}"
        }
      }

      warnings.toList
    }
  }
}

object ConfigManagementService extends App {
  import JsonProtocol._

  implicit val system: ActorSystem = ActorSystem("config-management-system")
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  case class LookupRequest(xml: String, key: String)
  case class SectionRequest(xml: String, section: String)
  case class LookupResponse(success: Boolean, setting: Option[ConfigSetting], error: Option[String])
  case class SectionResponse(success: Boolean, settings: List[ConfigSetting], error: Option[String])
  case class ValidationResponse(success: Boolean, warnings: List[String], error: Option[String])

  implicit val lookupRequestFormat: RootJsonFormat[LookupRequest] = jsonFormat2(LookupRequest)
  implicit val sectionRequestFormat: RootJsonFormat[SectionRequest] = jsonFormat2(SectionRequest)
  implicit val lookupResponseFormat: RootJsonFormat[LookupResponse] = jsonFormat3(LookupResponse)
  implicit val sectionResponseFormat: RootJsonFormat[SectionResponse] = jsonFormat3(SectionResponse)
  implicit val validationResponseFormat: RootJsonFormat[ValidationResponse] = jsonFormat3(ValidationResponse)

  val routes: Route = pathPrefix("api" / "config") {
    concat(
      // Parse full configuration
      path("parse") {
        post {
          entity(as[ParseRequest]) { request =>
            ConfigXmlParser.parseConfig(request.xml) match {
              case Right(config) =>
                complete(StatusCodes.OK, ParseResponse(success = true, Some(config), None))
              case Left(error) =>
                complete(StatusCodes.BadRequest, ParseResponse(success = false, None, Some(error)))
            }
          }
        }
      },

      // Look up a specific setting by key
      path("lookup") {
        post {
          entity(as[LookupRequest]) { request =>
            ConfigXmlParser.extractSettingByKey(request.xml, request.key) match {
              case Right(setting) =>
                complete(StatusCodes.OK, LookupResponse(success = true, setting, None))
              case Left(error) =>
                complete(StatusCodes.BadRequest, LookupResponse(success = false, None, Some(error)))
            }
          }
        }
      },

      // Get all settings in a section
      path("section") {
        post {
          entity(as[SectionRequest]) { request =>
            ConfigXmlParser.extractSettingsBySection(request.xml, request.section) match {
              case Right(settings) =>
                complete(StatusCodes.OK, SectionResponse(success = true, settings, None))
              case Left(error) =>
                complete(StatusCodes.BadRequest, SectionResponse(success = false, List.empty, Some(error)))
            }
          }
        }
      },

      // Validate configuration
      path("validate") {
        post {
          entity(as[ParseRequest]) { request =>
            ConfigXmlParser.validateConfig(request.xml) match {
              case Right(warnings) =>
                complete(StatusCodes.OK, ValidationResponse(success = true, warnings, None))
              case Left(error) =>
                complete(StatusCodes.BadRequest, ValidationResponse(success = false, List.empty, Some(error)))
            }
          }
        }
      },

      // Health check
      path("health") {
        get {
          complete(StatusCodes.OK, JsObject("status" -> JsString("healthy")))
        }
      }
    )
  }

  val bindingFuture = Http().newServerAt("0.0.0.0", 8080).bind(routes)

  bindingFuture.onComplete {
    case Success(binding) =>
      val address = binding.localAddress
      println(s"Configuration Management Service running at http://${address.getHostString}:${address.getPort}/")
      println("Endpoints:")
      println("  POST /api/config/parse    - Parse full XML configuration")
      println("  POST /api/config/lookup   - Look up a setting by key")
      println("  POST /api/config/section  - Get settings by section name")
      println("  POST /api/config/validate - Validate XML configuration")
      println("  GET  /api/config/health   - Health check")
    case Failure(ex) =>
      println(s"Failed to bind to port 8080: ${ex.getMessage}")
      system.terminate()
  }
}